      var scatterPath = 'M ' + sunX + ' ' + sunY + ' L ' + deflectX.toFixed(1) + ' ' + deflectY.toFixed(1);
      // Time-tuned durations: light still travels at c — we use the survival
      // path duration as the baseline so survivors all reach the observer
