          style: { padding: '4px 8px', background: rate === 'fast' ? '#7e22ce' : 'rgba(168,85,247,0.20)', color: '#fff', border: 'none', borderRadius: 4, fontSize: 10, fontWeight: 700, cursor: 'pointer' }
